{"path": "/tmp/sv-a493888fd0ae447398d4e39f41e11f1c/Components/Pages/Catalog/ProductCard.razor", "file_text": "
<div class="card h-100 product-card @(Product.InStock ? "" : "border-secondary")"
     @onclick="HandleCardClick"
     style="cursor: pointer;">
    <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
         style="height: 180px;"
         role="img"
         aria-label="@Product.Name">
        <span class="text-muted fs-5">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h5 class="card-title text-truncate" title="@Product.Name">@Product.Name</h5>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @GetStarRating(Product.Rating)
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-secondary mb-2">Out of Stock</span>
        }
        <button class="btn @(Product.InStock ? "btn-primary" : "btn-outline-secondary") mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}
"}

